export function getIcon(name, className = '') {
  const iconSvg = icons[name] || '';
  if (!iconSvg) return '';
  if (className) {
    return iconSvg.replace('<svg ', `<svg class="${className}" `);
  }
  return iconSvg;
}

export default getIcon;
